SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vf_chq_to_bank (seq_no, bank_name, cheque_no, item_amount, vourcher_no, bank_fin, owner_name, chq_desc) AS select seq_no , bank_name ,cheque_no , item_amount , vourcher_no , bank_fin , owner_name ,  chq_desc
  FROM (

    select 1 as seq_no 
    ,  sc_acc_m_ucf_bank.bank_name as bank_name
    ,  sc_com_m_receipt.cheque_no   as cheque_no
    ,  sc_com_m_receipt.recept_amount as item_amount
    , sc_com_m_receipt.vourcher_no as vourcher_no
    , sc_fin_cheque_tobank.bank_fin as bank_fin
    , pka_com_function.fp_get_member_name(sc_com_m_receipt.membership_no) || ' สมาชิกเลขที่ ' || sc_com_m_receipt.membership_no as owner_name
    , 'ชำระหนี้ใบเสร็จเลขที่ ' || sc_com_m_receipt.receipt_no as chq_desc
    FROM sc_acc_m_ucf_bank,   
         sc_fin_cheque_tobank,   
         sc_com_m_receipt  
   WHERE ( sc_acc_m_ucf_bank.bank_id = sc_com_m_receipt.acc_bank ) and ( sc_fin_cheque_tobank.cheque_no = sc_com_m_receipt.cheque_no ) and ( sc_fin_cheque_tobank.cancel_status = '0' )      


union all
 

    select sc_dep_t_deposit_slip_item.seq_no   as seq_no
    ,  sc_acc_m_ucf_bank.bank_name as bank_name
    ,  sc_dep_t_deposit_slip_item.chq_no as cheque_no
    ,  sc_dep_t_deposit_slip_item.item_amount  as item_amount
    , sc_dep_t_deposit_slip.vourcher_no as vourcher_no
    , sc_fin_cheque_tobank.bank_fin as bank_fin
    , pka_com_function.fp_get_member_name(sc_dep_m_creditor.membership_no) || ' สมาชิกเลขที่ ' || sc_dep_m_creditor.membership_no as owner_name
    , 'ฝากเข้าบัญชี ' || pka_com_function.fp_form_depno( sc_dep_m_creditor.deposit_account_no )   as chq_desc
    FROM sc_dep_t_deposit_slip_item,   
         sc_acc_m_ucf_bank,   
         sc_fin_cheque_tobank,   
         sc_dep_t_deposit_slip ,
         sc_dep_m_creditor
   WHERE sc_dep_m_creditor.deposit_account_no = sc_dep_t_deposit_slip.account_no and ( sc_dep_t_deposit_slip_item.chq_bank = sc_acc_m_ucf_bank.bank_id ) and ( sc_fin_cheque_tobank.vourcher_no = sc_dep_t_deposit_slip.vourcher_no ) and ( sc_dep_t_deposit_slip_item.deposit_slip_no = sc_dep_t_deposit_slip.deposit_slip_no ) and ( sc_fin_cheque_tobank.cheque_no = sc_dep_t_deposit_slip_item.chq_no ) and ( sc_fin_cheque_tobank.cancel_status = '0'  )     
         

union all
 

   select 1 as seq_no 
    ,  sc_acc_m_ucf_bank.bank_name as bank_name
    ,  sc_inv_bill_receipt.cheque_no   as cheque_no
    ,  sum( sc_fin_cheque_tobank.cheque_amount ) as item_amount
    ,  sc_inv_bill_receipt.vourcher_no as vourcher_no
    ,  sc_fin_cheque_tobank.bank_fin as bank_fin
    ,  pka_com_function.fp_get_member_name(sc_inv_bill.membership_no)  as owner_name
    , 'รับผลตอบแทนใบเสร็จเลขที่ ' || sc_inv_bill_receipt.receipt_no as chq_desc
    FROM sc_acc_m_ucf_bank,   
         sc_fin_cheque_tobank,   
         sc_inv_bill_receipt  
        ,sc_inv_bill
   WHERE  1=1  
    and  sc_inv_bill.bill_no = sc_inv_bill_receipt.bill_no  
    and  sc_acc_m_ucf_bank.bank_id = sc_inv_bill_receipt.bank_id   
    and  sc_fin_cheque_tobank.cheque_no = sc_inv_bill_receipt.cheque_no       
    and  sc_fin_cheque_tobank.cancel_status = '0'      
    group by sc_acc_m_ucf_bank.bank_name 
    ,sc_inv_bill_receipt.cheque_no
    ,sc_inv_bill_receipt.vourcher_no
    ,sc_fin_cheque_tobank.bank_fin
    , sc_inv_bill.membership_no
    ,sc_inv_bill_receipt.receipt_no          
) tb 
where 1=1
/*WHERE*/

--and  vourcher_no = 'R66001352'
order by seq_no , cheque_no;

